// Node-RED Function node
// Outputs: 2
// Verzamelt alle 8 command-uplinks van 1 samplingronde.
// Pas als alles binnen is:
// - output 1 = meter 1
// - output 2 = meter 2

const DEV_MAP = {
    0: "360002032026090101", // slave 01
    1: "360002032026090102"  // slave 02
};

const CHANNELS = [
    { prop: "total_system_power_W", reg: 0x0034, id: 4200 },
    { prop: "total_system_var_VAr", reg: 0x003C, id: 4300 },
    { prop: "total_export_kWh", reg: 0x0048, id: 4500 },
    { prop: "total_import_kWh", reg: 0x004A, id: 4600 },
    { prop: "total_export_kVArh", reg: 0x004C, id: 4700 },
    { prop: "total_import_kVArh", reg: 0x004E, id: 4800 },
    { prop: "total_system_power_factor", reg: 0x003E, id: 4400 },
    { prop: "max_system_power_demand_VA", reg: 0x0056, id: 5700 }
];

const SCALE_BY_1000 = [4200, 4300, 5700, 5800];

const HEADER_LEN = 5;
const DEVICE_COUNT = 2;
const BYTES_PER_DEVICE = 5;   // 1 byte slave address + 4 bytes float
const BATCH_TIMEOUT_MS = 120000;

function readFloatBE(buf, off) {
    if (off + 4 > buf.length) return null;
    const v = buf.readFloatBE(off);
    if (!isFinite(v)) return null;
    return Math.round(v * 1000) / 1000;
}

function scaleValue(id, val) {
    if (val == null) return val;
    if (SCALE_BY_1000.includes(id)) {
        return Math.round((val / 1000) * 1000) / 1000;
    }
    return val;
}

function buildResult(dev, ts, mid, mdList, edList) {
    return {
        MID: mid,
        D: [{
            Dev: dev,
            TS: ts,
            ED: edList || [],
            MD: mdList || []
        }]
    };
}

let buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload;

if (!Buffer.isBuffer(buf) || buf.length < HEADER_LEN) {
    node.error("Invalid payload buffer", msg);
    return null;
}

const battery = (((buf[0] << 8) | buf[1]) & 0x7fff) / 1000;
const payver = buf[2];
const payloadCount = buf[3];
const payloadNumber = buf[4];
const ts = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString();

if (payloadNumber >= CHANNELS.length) {
    node.warn("Unknown payloadNumber: " + payloadNumber);
    return null;
}

const sourceKey =
    msg.devEui ||
    msg.deveui ||
    msg.deviceEUI ||
    msg.topic ||
    "default_dragino";

let batches = context.get("batches") || {};
let batch = batches[sourceKey];

const now = Date.now();
const isExpired = batch && (now - batch.createdAt > BATCH_TIMEOUT_MS);

if (!batch || payloadNumber === 0 || isExpired) {
    batch = {
        createdAt: now,
        expectedCount: payloadCount,
        battery,
        payver,
        ts,
        segments: {}
    };
}

batch.segments[payloadNumber] = Buffer.from(buf);
batch.expectedCount = payloadCount;
batch.battery = battery;
batch.payver = payver;
batch.ts = ts;

batches[sourceKey] = batch;
context.set("batches", batches);

let complete = true;
for (let i = 0; i < batch.expectedCount; i++) {
    if (!batch.segments[i]) {
        complete = false;
        break;
    }
}

if (!complete) {
    return null;
}

let deviceData = {
    0: { md: [], ed: [] },
    1: { md: [], ed: [] }
};

for (let segNo = 0; segNo < batch.expectedCount; segNo++) {
    const seg = batch.segments[segNo];
    const ch = CHANNELS[segNo];
    if (!ch) continue;

    for (let slot = 0; slot < DEVICE_COUNT; slot++) {
        const base = HEADER_LEN + (slot * BYTES_PER_DEVICE);

        if (base + BYTES_PER_DEVICE > seg.length) {
            deviceData[slot].ed.push({
                Id: 9001,
                Msg: "Segment too short for device slot " + slot + " in payload " + segNo
            });
            continue;
        }

        const slaveAddr = seg[base];
        const floatOff = base + 1;
        const rawData = seg.slice(floatOff, floatOff + 4);

        const allFFAddr = (slaveAddr === 0xFF);
        const allFFData = rawData.every(b => b === 0xFF);

        if (allFFAddr && allFFData) {
            deviceData[slot].ed.push({
                Id: 9002,
                Msg: "No response / invalid data for metric " + ch.id
            });
            continue;
        }

        let value = readFloatBE(seg, floatOff);

        if (value == null || rawData.every(b => b === 0xFF)) {
            deviceData[slot].ed.push({
                Id: 9003,
                Msg: "Invalid float value for metric " + ch.id
            });
            continue;
        }

        value = scaleValue(ch.id, value);

        deviceData[slot].md.push({
            Id: ch.id,
            Val: value
        });
    }
}

let mid = global.get("mid") || 0;
let outputs = [null, null];

for (let slot = 0; slot < DEVICE_COUNT; slot++) {
    const dev = DEV_MAP[slot];

    let mdList = [
        ...deviceData[slot].md,
        { Id: 7200, Val: batch.battery },
        { Id: 9100, Val: batch.payver },
        { Id: 9101, Val: batch.expectedCount }
    ];

    if (msg.snr !== undefined) {
        mdList.push({ Id: 5400, Val: parseFloat(msg.snr) });
    }

    if (msg.rssi !== undefined) {
        mdList.push({ Id: 5500, Val: parseFloat(msg.rssi) });
    }

    if (msg.dr && msg.dr.spreadFactor !== undefined) {
        mdList.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) });
    }

    outputs[slot] = {
        ...msg,
        payload: buildResult(dev, batch.ts, mid, mdList, deviceData[slot].ed)
    };

    mid++;
}

global.set("mid", mid);

delete batches[sourceKey];
context.set("batches", batches);

return outputs;
